// Safe combine (handles undefined + trims)
const text = (
  ($json.title || "") + " " + ($json.description || "")
).toLowerCase().trim();

// Debug (VERY IMPORTANT)
console.log("TEXT:", text);

let keywords = [
  "inflation",
  "interest",
  "rate",
  "usd",
  "inr",
  "fed",
  "fomc",
  "rbi",
  "central bank",
  "monetary",
  "policy",
  "gdp",
  "economy",
  "trade",
  "exports",
  "imports",
  "deficit",
  "surplus",
  "oil",
  "energy"
];

let matched = [];

for (let word of keywords) {
  if (text.includes(word)) {
    matched.push(word);
  }
}

let isRelevant = matched.length > 0;

return [
  {
    json: {
      ...$json,
      is_relevant: isRelevant,
      matched_keywords: matched,
      filter_reason: isRelevant
        ? `Relevant due to: ${matched.join(", ")}`
        : "Not relevant: No forex-related keywords found"
    }
  }
];

// Step 1: Safely extract AI text from ANY structure
let raw = "";

// Try multiple possible paths (robust handling)
if ($json.output?.[0]?.content?.[0]?.text) {
  raw = $json.output[0].content[0].text;
} else if ($json.text) {
  raw = $json.text;
} else if ($json.message?.content) {
  raw = $json.message.content;
}

// Fail if nothing found
if (!raw) {
  throw new Error("No AI output found in response");
}

// Step 2: Clean markdown
raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

// Step 3: Parse JSON
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  console.log("RAW OUTPUT:", raw);
  throw new Error("Invalid JSON from AI");
}

// Step 4: Merge with ORIGINAL data (CRITICAL)
return [
  {
    json: {
      ...$json,   // keeps title, description, etc.
      ...parsed   // adds AI output
    }
  }
];

// ===== Reuse existing data =====
const data = $json;

// ===== Risk Scoring =====
let score = data.confidence_score || 50;

if (data.risk_level?.toLowerCase() === "high") score += 20;
else if (data.risk_level?.toLowerCase() === "medium") score += 10;
else score -= 10;

if (data.impact?.toLowerCase().includes("bearish")) score += 5;

if (score > 100) score = 100;
if (score < 0) score = 0;

// ===== Priority =====
let priority = "LOW";
if (score >= 80) priority = "HIGH";
else if (score >= 60) priority = "MEDIUM";

// ===== Dedupe Key =====
const title = data.title || "";
const dedupe_key = title
  .toLowerCase()
  .replace(/[^\w\s]/g, "")
  .trim();

// ===== Return =====
return [
  {
    json: {
      ...data,
      final_score: score,
      priority,
      dedupe_key
    }
  }
];
